program LIPDecide;
uses sysutils, math;

const
  PI = 3.1415926535;
  MAX_POINTS = 100;
  MAX_LICS = 15;

type
  POINTRANGE  = 1..MAX_POINTS;
  LICRANGE    = 1..MAX_LICS;
  NPOINTS     = 2..MAX_POINTS;
  NPTYPE      = 3..MAX_POINTS;
  CONNECTORS  = (NOTUSED, ORR, ANDD);
  NUMQUADS    = 1..3;
  COORDINATE  = array[POINTRANGE] of real;
  CMATRIX     = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX     = array[LICRANGE, LICRANGE] of boolean;
  VECTOR      = array[LICRANGE] of boolean;
  COMPTYPE    = (LT, EQ, GT);

var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : NPOINTS;
  PARAMETERS : record
    LENGTH1  : real;
    RADIUS1  : real;
    EPSILON  : real;
    AREA1    : real;
    Q_PTS    : NPOINTS;
    QUADS    : NUMQUADS;
    DIST     : real;
    N_PTS    : NPTYPE;
    K_PTS    : POINTRANGE;
    A_PTS    : POINTRANGE;
    B_PTS    : POINTRANGE;
    C_PTS    : POINTRANGE;
    D_PTS    : POINTRANGE;
    E_PTS    : POINTRANGE;
    F_PTS    : POINTRANGE;
    G_PTS    : POINTRANGE;
    LENGTH2  : real;
    RADIUS2  : real;
    AREA2    : real;
  end;
  LCM     : CMATRIX;
  PUM     : BMATRIX;
  CMV     : VECTOR;
  FUV     : VECTOR;
  LAUNCH  : boolean;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
end;

function GetQuadrant(x, y: real): integer;
begin
  if REALCOMPARE(x, 0) = EQ then
  begin
    if REALCOMPARE(y, 0) = EQ then
      GetQuadrant := 1
    else if REALCOMPARE(y, 0) = GT then
      GetQuadrant := 1
    else
      GetQuadrant := 3;
  end
  else if REALCOMPARE(x, 0) = GT then
  begin
    if REALCOMPARE(y, 0) = EQ then
      GetQuadrant := 1
    else if REALCOMPARE(y, 0) = GT then
      GetQuadrant := 1
    else
      GetQuadrant := 4;
  end
  else
  begin
    if REALCOMPARE(y, 0) = EQ then
      GetQuadrant := 2
    else if REALCOMPARE(y, 0) = GT then
      GetQuadrant := 2
    else
      GetQuadrant := 3;
  end;
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0);
end;

function AngleBetweenPoints(x1, y1, x2, y2, x3, y3: real): real;
var
  d1, d2, dot, angle: real;
begin
  d1 := Distance(x2, y2, x1, y1);
  d2 := Distance(x2, y2, x3, y3);

  if (REALCOMPARE(d1, 0) = EQ) or (REALCOMPARE(d2, 0) = EQ) then
    AngleBetweenPoints := -1
  else
  begin
    dot := (x1 - x2) * (x3 - x2) + (y1 - y2) * (y3 - y2);
    angle := arccos(dot / (d1 * d2));
    AngleBetweenPoints := angle;
  end;
end;

function MinimalEnclosingCircleRadius(x1, y1, x2, y2, x3, y3: real): real;
var
  d12, d23, d31, area, radius: real;
begin
  d12 := Distance(x1, y1, x2, y2);
  d23 := Distance(x2, y2, x3, y3);
  d31 := Distance(x3, y3, x1, y1);
  area := TriangleArea(x1, y1, x2, y2, x3, y3);

  if REALCOMPARE(area, 0) = EQ then
  begin
    radius := max(max(d12, d23), d31) / 2.0;
  end
  else
  begin
    radius := (d12 * d23 * d31) / (4.0 * area);
  end;

  MinimalEnclosingCircleRadius := radius;
end;

function PointToLineDistance(px, py, x1, y1, x2, y2: real): real;
var
  dist, denom, num: real;
begin
  if REALCOMPARE(x1, x2) = EQ then
  begin
    if REALCOMPARE(y1, y2) = EQ then
      PointToLineDistance := Distance(px, py, x1, y1)
    else
      PointToLineDistance := abs(px - x1);
  end
  else
  begin
    denom := sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
    num := abs((y2 - y1) * px - (x2 - x1) * py + x2 * y1 - y2 * x1);
    PointToLineDistance := num / denom;
  end;
end;

procedure EvaluateLIC1;
var
  i: integer;
begin
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(Distance(X[i], Y[i], X[i + 1], Y[i + 1]), PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := true;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC2;
var
  i: integer;
  radius: real;
begin
  CMV[2] := false;
  if NUMPOINTS < 3 then Exit;

  for i := 1 to NUMPOINTS - 2 do
  begin
    radius := MinimalEnclosingCircleRadius(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(radius, PARAMETERS.RADIUS1) = GT then
    begin
      CMV[2] := true;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC3;
var
  i: integer;
  angle: real;
begin
  CMV[3] := false;
  if NUMPOINTS < 3 then Exit;

  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := AngleBetweenPoints(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if angle >= 0 then
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CMV[3] := true;
        Exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC4;
var
  i: integer;
  area: real;
begin
  CMV[4] := false;
  if NUMPOINTS < 3 then Exit;

  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := true;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC5;
var
  i, j, quad_count, quad_set: integer;
  q: integer;
begin
  CMV[5] := false;
  if NUMPOINTS < PARAMETERS.Q_PTS then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quad_set := 0;
    for j := i to i + PARAMETERS.Q_PTS - 1 do
    begin
      q := GetQuadrant(X[j], Y[j]);
      if (quad_set and (1 shl q)) = 0 then
      begin
        quad_set := quad_set or (1 shl q);
      end;
    end;

    quad_count := 0;
    if (quad_set and (1 shl 1)) <> 0 then quad_count += 1;
    if (quad_set and (1 shl 2)) <> 0 then quad_count += 1;
    if (quad_set and (1 shl 3)) <> 0 then quad_count += 1;
    if (quad_set and (1 shl 4)) <> 0 then quad_count += 1;

    if quad_count > PARAMETERS.QUADS then
    begin
      CMV[5] := true;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC6;
var
  i: integer;
begin
  CMV[6] := false;
  if NUMPOINTS < 2 then Exit;

  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i + 1] - X[i], 0) = LT then
    begin
      CMV[6] := true;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC7;
var
  i, j: integer;
  max_dist: real;
begin
  CMV[7] := false;
  if NUMPOINTS < 3 then Exit;
  if PARAMETERS.N_PTS > NUMPOINTS then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    max_dist := 0;
    for j := i to i + PARAMETERS.N_PTS - 1 do
    begin
      if REALCOMPARE(PointToLineDistance(X[j], Y[j], X[i], Y[i], X[i + PARAMETERS.N_PTS - 1], Y[i + PARAMETERS.N_PTS - 1]), max_dist) = GT then
        max_dist := PointToLineDistance(X[j], Y[j], X[i], Y[i], X[i + PARAMETERS.N_PTS - 1], Y[i + PARAMETERS.N_PTS - 1]);
    end;

    if REALCOMPARE(max_dist, PARAMETERS.DIST) = GT then
    begin
      CMV[7] := true;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC8;
var
  i: integer;
  j: integer;
begin
  CMV[8] := false;
  if NUMPOINTS < 3 then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    if REALCOMPARE(Distance(X[i], Y[i], X[j], Y[j]), PARAMETERS.LENGTH1) = GT then
    begin
      CMV[8] := true;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC9;
var
  i, j, k: integer;
  radius: real;
begin
  CMV[9] := false;
  if NUMPOINTS < 5 then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if k <= NUMPOINTS then
    begin
      radius := MinimalEnclosingCircleRadius(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(radius, PARAMETERS.RADIUS1) = GT then
      begin
        CMV[9] := true;
        Exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC10;
var
  i, j, k: integer;
  angle: real;
begin
  CMV[10] := false;
  if NUMPOINTS < 5 then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    if k <= NUMPOINTS then
    begin
      angle := AngleBetweenPoints(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if angle >= 0 then
      begin
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
           (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        begin
          CMV[10] := true;
          Exit;
        end;
      end;
    end;
  end;
end;

procedure EvaluateLIC11;
var
  i, j, k: integer;
  area: real;
begin
  CMV[11] := false;
  if NUMPOINTS < 5 then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    if k <= NUMPOINTS then
    begin
      area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      begin
        CMV[11] := true;
        Exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC12;
var
  i, j: integer;
begin
  CMV[12] := false;
  if NUMPOINTS < 3 then Exit;

  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    j := i + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[j] - X[i], 0) = LT then
    begin
      CMV[12] := true;
      Exit;
    end;
  end;
end;

procedure EvaluateLIC13;
var
  i, j: integer;
  found_gt, found_lt: boolean;
begin
  CMV[13] := false;
  if NUMPOINTS < 3 then Exit;

  found_gt := false;
  found_lt := false;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    if REALCOMPARE(Distance(X[i], Y[i], X[j], Y[j]), PARAMETERS.LENGTH1) = GT then
      found_gt := true;
    if REALCOMPARE(Distance(X[i], Y[i], X[j], Y[j]), PARAMETERS.LENGTH2) = LT then
      found_lt := true;
  end;

  CMV[13] := found_gt and found_lt;
end;

procedure EvaluateLIC14;
var
  i, j, k: integer;
  radius: real;
  found_gt, found_lt: boolean;
begin
  CMV[14] := false;
  if NUMPOINTS < 5 then Exit;

  found_gt := false;
  found_lt := false;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if k <= NUMPOINTS then
    begin
      radius := MinimalEnclosingCircleRadius(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(radius, PARAMETERS.RADIUS1) = GT then
        found_gt := true;
      if REALCOMPARE(radius, PARAMETERS.RADIUS2) = LT then
        found_lt := true;
    end;
  end;

  CMV[14] := found_gt and found_lt;
end;

procedure EvaluateLIC15;
var
  i, j, k: integer;
  area: real;
  found_gt, found_lt: boolean;
begin
  CMV[15] := false;
  if NUMPOINTS < 5 then Exit;

  found_gt := false;
  found_lt := false;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    if k <= NUMPOINTS then
    begin
      area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
        found_gt := true;
      if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
        found_lt := true;
    end;
  end;

  CMV[15] := found_gt and found_lt;
end;

procedure DECIDE;
var
  i, j: integer;
  all_true: boolean;
begin
  EvaluateLIC1;
  EvaluateLIC2;
  EvaluateLIC3;
  EvaluateLIC4;
  EvaluateLIC5;
  EvaluateLIC6;
  EvaluateLIC7;
  EvaluateLIC8;
  EvaluateLIC9;
  EvaluateLIC10;
  EvaluateLIC11;
  EvaluateLIC12;
  EvaluateLIC13;
  EvaluateLIC14;
  EvaluateLIC15;

  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then
        Continue;

      if LCM[i, j] = NOTUSED then
        PUM[i, j] := true
      else if LCM[i, j] = ANDD then
        PUM[i, j] := CMV[i] and CMV[j]
      else
        PUM[i, j] := CMV[i] or CMV[j];
    end;
  end;

  for i := 1 to 15 do
  begin
    all_true := true;
    for j := 1 to 15 do
    begin
      if i <> j then
      begin
        if not PUM[i, j] then
        begin
          all_true := false;
          Break;
        end;
      end;
    end;

    FUV[i] := (not PUM[i, i]) or all_true;
  end;

  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      Break;
    end;
  end;
end;

begin
  DECIDE;
end.
